import { ImageResponse } from "next/og"
import type { NextRequest } from "next/server"

export const runtime = "edge"

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const title = searchParams.get("title") || "Article"
    const author = searchParams.get("author") || "Vibe Coding Team"
    const readTime = searchParams.get("readTime") || "5"
    const tags = searchParams.get("tags")?.split(",") || []
    const publishedAt = searchParams.get("publishedAt") || new Date().toLocaleDateString("ko-KR")

    return new ImageResponse(
      <div
        style={{
          height: "100%",
          width: "100%",
          display: "flex",
          flexDirection: "column",
          backgroundColor: "#ffffff",
          backgroundImage: "linear-gradient(135deg, #f0fdf4 0%, #ecfdf5 100%)",
          position: "relative",
        }}
      >
        {/* Background Pattern */}
        <div
          style={{
            position: "absolute",
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundImage: `url("data:image/svg+xml,%3Csvg width='40' height='40' viewBox='0 0 40 40' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='%23059669' fillOpacity='0.03'%3E%3Cpath d='M20 20c0-5.5-4.5-10-10-10s-10 4.5-10 10 4.5 10 10 10 10-4.5 10-10zm10 0c0-5.5-4.5-10-10-10s-10 4.5-10 10 4.5 10 10 10 10-4.5 10-10z'/%3E%3C/g%3E%3C/svg%3E")`,
          }}
        />

        {/* Header */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            padding: "40px 60px 0",
          }}
        >
          <div
            style={{
              display: "flex",
              alignItems: "center",
            }}
          >
            <div
              style={{
                width: "50px",
                height: "50px",
                backgroundColor: "#059669",
                borderRadius: "10px",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                marginRight: "16px",
              }}
            >
              <svg
                width="24"
                height="24"
                viewBox="0 0 24 24"
                fill="none"
                stroke="white"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
              >
                <polyline points="16,18 22,12 16,6" />
                <polyline points="8,6 2,12 8,18" />
              </svg>
            </div>
            <div
              style={{
                fontSize: "24px",
                fontWeight: "900",
                color: "#1f2937",
                fontFamily: "system-ui, -apple-system, sans-serif",
              }}
            >
              Vibe Coding Blog
            </div>
          </div>

          <div
            style={{
              backgroundColor: "#059669",
              color: "white",
              padding: "8px 16px",
              borderRadius: "20px",
              fontSize: "14px",
              fontWeight: "600",
              fontFamily: "system-ui, -apple-system, sans-serif",
            }}
          >
            ARTICLE
          </div>
        </div>

        {/* Main Content */}
        <div
          style={{
            flex: 1,
            display: "flex",
            flexDirection: "column",
            justifyContent: "center",
            padding: "40px 60px",
          }}
        >
          <h1
            style={{
              fontSize: "52px",
              fontWeight: "900",
              color: "#1f2937",
              lineHeight: "1.1",
              marginBottom: "30px",
              fontFamily: "system-ui, -apple-system, sans-serif",
            }}
          >
            {title}
          </h1>

          {/* Tags */}
          {tags.length > 0 && (
            <div
              style={{
                display: "flex",
                flexWrap: "wrap",
                gap: "8px",
                marginBottom: "30px",
              }}
            >
              {tags.slice(0, 4).map((tag, index) => (
                <span
                  key={index}
                  style={{
                    backgroundColor: "#dcfce7",
                    color: "#166534",
                    padding: "6px 12px",
                    borderRadius: "6px",
                    fontSize: "14px",
                    fontWeight: "500",
                    fontFamily: "system-ui, -apple-system, sans-serif",
                  }}
                >
                  {tag.trim()}
                </span>
              ))}
            </div>
          )}

          {/* Author and Meta */}
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: "24px",
            }}
          >
            <div
              style={{
                display: "flex",
                alignItems: "center",
              }}
            >
              <div
                style={{
                  width: "40px",
                  height: "40px",
                  backgroundColor: "#e5e7eb",
                  borderRadius: "50%",
                  marginRight: "12px",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                }}
              >
                <svg
                  width="20"
                  height="20"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="#6b7280"
                  strokeWidth="2"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                >
                  <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" />
                  <circle cx="12" cy="7" r="4" />
                </svg>
              </div>
              <span
                style={{
                  fontSize: "18px",
                  color: "#374151",
                  fontWeight: "600",
                  fontFamily: "system-ui, -apple-system, sans-serif",
                }}
              >
                {author}
              </span>
            </div>

            <div
              style={{
                display: "flex",
                alignItems: "center",
                color: "#6b7280",
                fontSize: "16px",
                fontFamily: "system-ui, -apple-system, sans-serif",
              }}
            >
              <svg
                width="16"
                height="16"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
                style={{ marginRight: "6px" }}
              >
                <circle cx="12" cy="12" r="10" />
                <polyline points="12,6 12,12 16,14" />
              </svg>
              {readTime}분 읽기
            </div>

            <div
              style={{
                color: "#6b7280",
                fontSize: "16px",
                fontFamily: "system-ui, -apple-system, sans-serif",
              }}
            >
              {publishedAt}
            </div>
          </div>
        </div>

        {/* Footer */}
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            padding: "0 60px 40px",
          }}
        >
          <div
            style={{
              color: "#9ca3af",
              fontSize: "16px",
              fontFamily: "system-ui, -apple-system, sans-serif",
            }}
          >
            tech.restyart.com
          </div>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              color: "#9ca3af",
              fontSize: "14px",
              fontFamily: "system-ui, -apple-system, sans-serif",
            }}
          >
            Interactive Technical Blog Platform
          </div>
        </div>
      </div>,
      {
        width: 1200,
        height: 630,
      },
    )
  } catch (e: any) {
    console.log(`Failed to generate article OG image: ${e.message}`)
    return new Response(`Failed to generate the image`, {
      status: 500,
    })
  }
}
